sql:
SELECT SUM(amount) AS total_revenue
FROM payments
WHERE payment_status = 'completed';

SELECT name, rating 
FROM instructors
WHERE rating = (SELECT MAX(rating) FROM instructors);

external_knowledge:
- 'Rated above average' means the rating is greater than 3;
- 'Voyage has just begun' implies the course is still active;
- 'Without the anchor of a certificate' means no certificate has been issued yet;
- 'Voyages praised more than once' indicates the course has received multiple ratings;
- The stars given by students range from 1 to 5, with 3 being the average.

sql:
SELECT name, rating
FROM instructors
WHERE rating > (SELECT AVG(rating) FROM instructors);
